import React from 'react';
import Typography from '@material-ui/core/Typography';
import Grid from "@material-ui/core/Grid";

export default function Introduction() {
    return (
        <Grid container direction="column">
            <Grid item container sm >
            <Grid item style={{padding: 15}}>
                    <Typography variant="h4" color="inherit" >
                        My name is Yuval Kansal and I am currently a first year student enrolled in UNSW, Sydney
                        for the Bachelor of Computer Engineering (Honours). I am highly interested in Data
                        Science and Web Development through React. You can find me on LinkedIn or Github.
                        I am really passionate about discovering my passion in the future :p. In my free time,
                        I like to read fiction novels and play outdoor sports (preferably Cricket).
                    </Typography>
            </Grid>
            </Grid>
        </Grid>
    );
}
